class StringSignatureModule(dspy.Module):
    def __init__(self):
        super().__init__()
        # Pure-code deterministic judge. No predictors / no LM calls.

    def forward(self, **inputs):
        import re
        import math

        question = inputs.get("question", "") or ""
        response_a = inputs.get("response_a", "") or ""
        response_b = inputs.get("response_b", "") or ""

        STOP = set("""
            a an the and or but if then else of for to in on at by with from as is are was were be been
            being do does did have has had will would can could should may might must this that these those
            it its i you he she we they me him her us them my your his our their what which who whom how why
            when where about into over under again more most some any all no not so than too very just
        """.split())

        def tokenize(text):
            return re.findall(r"[a-zA-Z0-9]+", text.lower())

        def content_tokens(text):
            return [t for t in tokenize(text) if t not in STOP and len(t) > 1]

        def relevance(resp_tokens_set, q_tokens_set):
            # Jaccard-style overlap of question content words present in the response.
            if not q_tokens_set:
                return 0.0
            hits = len(resp_tokens_set & q_tokens_set)
            return hits / len(q_tokens_set)

        def type_token_ratio(tokens):
            # Lexical diversity: proxy for specificity / non-repetitive content.
            if not tokens:
                return 0.0
            return len(set(tokens)) / len(tokens)

        def specificity(text, tokens):
            # Fraction of tokens that are "concrete": numbers or longer/rarer words.
            if not tokens:
                return 0.0
            concrete = 0
            for t in tokens:
                if t.isdigit():
                    concrete += 1
                elif len(t) >= 6:
                    concrete += 1
            return concrete / len(tokens)

        def repetition_penalty(text):
            # Penalize duplicated sentences/lines (a hallmark of low-quality output).
            lines = [ln.strip() for ln in re.split(r"[\n.]+", text) if len(ln.strip()) > 15]
            if not lines:
                return 0.0
            uniq = len(set(lines))
            total = len(lines)
            return 1.0 - (uniq / total)  # 0 = no repetition, ->1 = heavy repetition

        def echo_penalty(text, question):
            # Penalize responses that just restate the question / prompt (off-task echo).
            q_norm = " ".join(tokenize(question))
            t_norm = " ".join(tokenize(text))
            if not q_norm or not t_norm:
                return 0.0
            if q_norm and q_norm in t_norm[: len(q_norm) + 40]:
                return 1.0
            return 0.0

        def code_junk_penalty(text, tokens):
            # Off-topic dumps (e.g. printing dir()/vars(), unrelated product reviews).
            if not tokens:
                return 0.0
            # readability: ratio of alphabetic characters
            alpha = sum(1 for c in text if c.isalpha())
            total = max(len(text), 1)
            return 1.0 - (alpha / total)  # more symbols/noise -> higher penalty

        def truncation_penalty(text):
            # Responses cut off mid-word/sentence are less complete.
            stripped = text.rstrip()
            if not stripped:
                return 1.0
            if stripped.endswith(("...", "…")):
                return 0.3
            last = stripped[-1]
            if last in ".!?)\"'`":
                return 0.0
            return 0.2

        def score(text):
            toks = tokenize(text)
            ctoks = content_tokens(text)
            resp_content_set = set(ctoks)
            q_content_set = set(content_tokens(question))

            rel = relevance(resp_content_set, q_content_set)      # 0..1 on-question
            ttr = type_token_ratio(toks)                          # 0..1 diversity
            spec = specificity(text, ctoks)                       # 0..1 concreteness
            rep = repetition_penalty(text)                        # 0..1 penalty
            echo = echo_penalty(text, question)                   # 0..1 penalty
            junk = code_junk_penalty(text, toks)                  # 0..1 penalty
            trunc = truncation_penalty(text)                      # 0..1 penalty

            # A minimum amount of content is needed to say anything at all;
            # but reward is saturating (log) so length can't dominate.
            content_amount = math.log1p(len(ctoks)) / 6.0
            content_amount = min(content_amount, 1.0)

            positive = (
                4.0 * rel +          # on-question relevance weighted most
                2.5 * spec +         # concrete / specific claims
                1.0 * ttr +          # lexical diversity (non-repetitive)
                0.8 * content_amount # some substance required (saturating)
            )
            penalties = (
                2.5 * rep +
                3.0 * echo +
                2.0 * junk +
                1.0 * trunc
            )
            return positive - penalties

        sa = score(response_a)
        sb = score(response_b)

        winner = "A" if sa >= sb else "B"
        return dspy.Prediction(winner=winner)

class StringSignatureModule(dspy.Module):
    def __init__(self):
        super().__init__()
        # Pure-code judge: NO predictors, NO LLM calls.

    def forward(self, **inputs):
        import re
        import math

        question = inputs.get("question", "") or ""
        response_a = inputs.get("response_a", "") or ""
        response_b = inputs.get("response_b", "") or ""

        STOP = {
            "the", "a", "an", "and", "or", "but", "if", "then", "else", "for",
            "to", "of", "in", "on", "at", "by", "with", "as", "is", "are",
            "was", "were", "be", "been", "being", "do", "does", "did", "how",
            "what", "why", "when", "where", "who", "which", "can", "could",
            "would", "should", "will", "shall", "may", "might", "must", "i",
            "you", "he", "she", "it", "we", "they", "me", "my", "your", "his",
            "her", "its", "our", "their", "this", "that", "these", "those",
            "from", "into", "about", "so", "not", "no", "yes", "than", "more",
            "less", "some", "any", "all", "each", "much", "many", "there",
            "here", "give", "given", "make", "please", "following", "want",
            "trying", "find", "good", "get", "got", "one", "also",
        }

        def tokens(text):
            return re.findall(r"[a-z0-9]+", text.lower())

        def content_tokens(text):
            return [t for t in tokens(text) if t not in STOP and len(t) > 2]

        def sentences(text):
            parts = re.split(r"[.!?\n]+", text)
            return [p.strip() for p in parts if p.strip()]

        q_content = set(content_tokens(question))
        # A normalized version of the question for echo-detection.
        q_norm = re.sub(r"\s+", " ", question.lower()).strip()

        def relevance(resp):
            # Fraction of question content words the response covers.
            if not q_content:
                return 0.5
            resp_set = set(content_tokens(resp))
            covered = len(q_content & resp_set)
            return covered / len(q_content)

        def repetition_penalty(resp):
            # Penalize degenerate repeated sentences (0 = clean, 1 = very repetitive).
            sents = sentences(resp)
            if len(sents) <= 1:
                return 0.0
            norm = [re.sub(r"\s+", " ", s.lower()) for s in sents]
            unique = len(set(norm))
            dup_ratio = 1.0 - (unique / len(norm))
            return dup_ratio

        def lexical_diversity(resp):
            words = tokens(resp)
            if not words:
                return 0.0
            return len(set(words)) / len(words)

        def readability(resp):
            sents = sentences(resp)
            if not sents:
                return 0.0
            lengths = [len(tokens(s)) for s in sents if tokens(s)]
            if not lengths:
                return 0.0
            avg = sum(lengths) / len(lengths)
            return math.exp(-((avg - 15.0) ** 2) / (2 * (10.0 ** 2)))

        def specificity(resp):
            words = tokens(resp)
            if not words:
                return 0.0
            numeric = sum(1 for w in words if any(c.isdigit() for c in w))
            return numeric / len(words)

        def off_topic_penalty(resp):
            # Detect responses that drift into unrelated content: measure how much
            # of the response's content is NOT related to the question at all.
            # We split the response into sentences and count the fraction of
            # sentences that share NO content word with the question.
            if not q_content:
                return 0.0
            sents = sentences(resp)
            if not sents:
                return 0.0
            off = 0
            total = 0
            for s in sents:
                st = set(content_tokens(s))
                if not st:
                    continue
                total += 1
                if not (st & q_content):
                    off += 1
            if total == 0:
                return 0.0
            return off / total

        def instruction_leak_penalty(resp):
            # Many degenerate outputs paste new fake "Instruction:/Input:/Output:"
            # blocks or restart with unrelated prompts. Penalize that.
            low = resp.lower()
            hits = 0
            for pat in ("instruction:", "input:", "output:", "\ntags:"):
                hits += low.count(pat)
            return min(hits, 4) / 4.0

        def echo_penalty(resp):
            # Penalize responses that merely restate the question rather than answer.
            if not q_norm or len(q_norm) < 10:
                return 0.0
            low = re.sub(r"\s+", " ", resp.lower())
            if q_norm in low:
                return 1.0
            # Partial: does the response begin by echoing the question wording?
            q_words = q_norm.split()
            if len(q_words) >= 4:
                frag = " ".join(q_words[:5])
                if frag in low:
                    return 0.5
            return 0.0

        def emptiness_penalty(resp):
            words = tokens(resp)
            if len(words) < 5:
                return 1.0
            return 0.0

        def code_leakage_penalty(resp):
            low = resp.lower()
            hits = 0
            for pat in ("import ", "print(", "def ", "```", "from ", "()"):
                if pat in low:
                    hits += 1
            return min(hits, 4) / 4.0

        def score(resp):
            rel = relevance(resp)                # completeness / on-question
            rep = repetition_penalty(resp)       # 0 good, 1 bad
            div = lexical_diversity(resp)
            read = readability(resp)
            spec = specificity(resp)
            off = off_topic_penalty(resp)        # 0 good, 1 bad
            leak = instruction_leak_penalty(resp)
            echo = echo_penalty(resp)
            empty = emptiness_penalty(resp)
            code = code_leakage_penalty(resp)

            s = 0.0
            s += 4.0 * rel          # completeness / relevance dominates
            s += 0.6 * div          # lexical diversity / directness
            s += 0.8 * read         # readability
            s += 0.3 * spec         # concrete detail (mild)

            s -= 2.5 * rep          # repetition (degenerate loops)
            s -= 3.0 * off          # drifting to unrelated topics
            s -= 2.0 * leak         # pasting fake instruction blocks
            s -= 2.0 * echo         # merely echoing the question
            s -= 3.0 * empty        # empty answers
            s -= 1.0 * code         # code dumps
            return s

        score_a = score(response_a)
        score_b = score(response_b)

        winner = "A" if score_a >= score_b else "B"
        return dspy.Prediction(winner=winner)
